// Extract email fields and check against family allowlist
const items = $input.all();
const results = [];

// CONFIGURE: Add family email addresses here
const familyAllowlist = [
  'ccimino2@gmail.com'
  // Add more family emails as needed
];

const knownSenders = [
  // Add known bill/notification senders
  // 'noreply@example.com'
];

for (const item of items) {
  const email = item.json;
  const from = (email.from || email.sender || '').toLowerCase();
  const fromEmail = from.match(/[\w.-]+@[\w.-]+/) ? from.match(/[\w.-]+@[\w.-]+/)[0] : from;

  const isFamily = familyAllowlist.some(f => fromEmail.includes(f.toLowerCase()));
  const isKnown = knownSenders.some(k => fromEmail.includes(k.toLowerCase()));

  results.push({
    json: {
      id: email.id,
      threadId: email.threadId,
      from: fromEmail,
      fromDisplay: from,
      subject: email.subject || '(no subject)',
      snippet: email.snippet || '',
      body: (email.text || email.snippet || '').substring(0, 2000),
      date: email.date || email.internalDate,
      isFamily: isFamily,
      isKnown: isKnown,
      route: isFamily ? 'family' : (isKnown ? 'known' : 'unknown')
    }
  });
}

return results;

