// Parse Claude's classification response
const item = $input.first();
const content = item.json.content;
let text = '';
if (Array.isArray(content)) {
  text = content.map(c => c.text || '').join('');
} else {
  text = content || '';
}

// Try to extract JSON from the response
let classification;
try {
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  classification = JSON.parse(jsonMatch[0]);
} catch (e) {
  classification = {
    category: 'conversation',
    confidence: 0.5,
    summary: 'Could not parse classification',
    draft_response: text,
    needs_chris: true
  };
}

// Merge with original email data from previous nodes
const emailData = $('Extract & Classify Sender').first().json;

return [{
  json: {
    ...emailData,
    classification: classification
  }
}];

